// Extract the article JSON from Claude's response
const response = $input.first().json;
const textContent = response.content[0].text;

// Parse the JSON from Claude's response
let article;
try {
  // Try direct parse
  article = JSON.parse(textContent);
} catch(e) {
  // If wrapped in markdown code block, extract it
  const match = textContent.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (match) {
    article = JSON.parse(match[1].trim());
  } else {
    throw new Error('Could not parse Claude response as JSON');
  }
}

return [{
  json: {
    title: article.title,
    meta_description: article.meta_description,
    content: article.content,
    tags: article.tags,
    category: article.category,
    keyword: $('خواندن کلمه کلیدی از شیت').first().json.keyword,
    row_number: $('خواندن کلمه کلیدی از شیت').first().json.row_number
  }
}];
